int sum(int arr[], int n) {
    int total = 0;
    for (int i = 0; i < n; i++)
        total += arr[i];
    return total;
}

int find_max(int *arr, int n) {
    int mx = arr[0];
    for (int i = 1; i < n; i++)
        if (arr[i] > mx) mx = arr[i];
    return mx;
}

int main() {
    int nums[] = {3, 1, 4, 1, 5};
    printf("sum: %d\n", sum(nums, 5));      // sum: 14
    printf("max: %d\n", find_max(nums, 5)); // max: 5
}

