int find_min(int arr[], int n) {
    int mn = arr[0];
    for (int i = 1; i < n; i++) {
        if (arr[i] < mn)
            mn = arr[i];
    }
    return mn;
}

int main() {
    int nums[] = {8, 3, 12, 1, 6};
    printf("%d\n", find_min(nums, 5));
    return 0;
}

