int add(int a, int b) { return a + b; }
int sub(int a, int b) { return a - b; }

int apply(int (*op)(int, int), int x, int y) {
    return op(x, y);
}

int main() {
    printf("%d\n", apply(add, 10, 3));  // 13
    printf("%d\n", apply(sub, 10, 3));  // 7
}

